const express = require('express');
const db = require('../database');
const router = express.Router();

router.post('/', (req, res) => {
  const { items, total, tax, discount, payment_method, cash_given, change_due, cashier_name } = req.body;

  db.serialize(() => {
    db.run('BEGIN TRANSACTION');

    db.run(
      `INSERT INTO transactions (total, tax, discount, payment_method, cash_given, change_due, cashier_name)
       VALUES (?, ?, ?, ?, ?, ?, ?)`,
      [total, tax, discount, payment_method, cash_given, change_due, cashier_name],
      function(err) {
        if (err) { db.run('ROLLBACK'); return res.status(500).json({ error: err.message }); }
        const transactionId = this.lastID;

        const stmt = db.prepare(`INSERT INTO transaction_items (transaction_id, product_id, product_name, quantity, price) VALUES (?, ?, ?, ?, ?)`);
        const updateStock = db.prepare(`UPDATE products SET stock = stock - ? WHERE id = ?`);

        items.forEach(item => {
          stmt.run(transactionId, item.product_id, item.name, item.quantity, item.price);
          updateStock.run(item.quantity, item.product_id);
        });

        stmt.finalize();
        updateStock.finalize();

        db.run('COMMIT', (err) => {
          if (err) { db.run('ROLLBACK'); return res.status(500).json({ error: err.message }); }
          res.json({ transactionId, success: true });
        });
      }
    );
  });
});

router.get('/', (req, res) => {
  const { date } = req.query;
  let query = 'SELECT * FROM transactions';
  let params = [];
  if (date) {
    query += ' WHERE DATE(created_at) = ?';
    params = [date];
  }
  db.all(query, params, (err, transactions) => {
    if (err) return res.status(500).json({ error: err.message });

    const promises = transactions.map(t => {
      return new Promise((resolve, reject) => {
        db.all('SELECT * FROM transaction_items WHERE transaction_id = ?', [t.id], (err, items) => {
          if (err) reject(err);
          t.items = items;
          resolve(t);
        });
      });
    });

    Promise.all(promises)
      .then(result => res.json(result))
      .catch(err => res.status(500).json({ error: err.message }));
  });
});

router.get('/:id', (req, res) => {
  const { id } = req.params;
  db.get('SELECT * FROM transactions WHERE id = ?', [id], (err, transaction) => {
    if (err) return res.status(500).json({ error: err.message });
    if (!transaction) return res.status(404).json({ error: 'Transaction not found' });

    db.all('SELECT * FROM transaction_items WHERE transaction_id = ?', [id], (err, items) => {
      if (err) return res.status(500).json({ error: err.message });
      transaction.items = items;
      res.json(transaction);
    });
  });
});

module.exports = router;
